(()=>{const parseExpr=expr=>{const match=expr.match(/(\d*)[dD](\d+)/);if(!match)return 0;const num=parseInt(match[1],10)||1;const dice=parseInt(match[2],10);return Array.from({length:num}).reduce((sum=>sum+randomInt(1,dice)),0)};const rollDice=expr=>{const replaced=expr.replace(/(\d*[dD]\d+)/g,(match=>parseExpr(match)));return eval(replaced)};Macro.add("evelexpr",{tags:null,handler(){if(this.args.length===0){return this.error("No provide expr")}const expr=this.args[0];if(typeof expr!=="string"){return this.error("Please provide string")}const result=rollDice(expr);WikiVars({result:result},this)}});setup.rollDice=rollDice;window.rollDice=window.rollDice||rollDice})();
